```

There is no `try`, `throw`, `catch` (as a keyword for exceptions), `raise`,
`except`, or `finally`. Error handling uses `Result(Ok, Err)`.
```
-- WRONG:
try { risky() } catch (e) { ... }
throw MyError()

-- CORRECT:
fn risky() -> Result(i32, MyError) { ... }
match risky() {
    .ok(v)  => { ... }
    .err(e) => { ... }
}
```

Note: `catch` IS a keyword in Pak but it works as a postfix expression on
`Result` values, not as an exception mechanism. See `LANGUAGE.md`.

```
-- WRONG:
let val = might_fail()?

-- CORRECT:
let result = might_fail()
let val = result catch |e| { return err(e) }
-- or:
match might_fail() {
    .ok(v)  => { ... }
    .err(e) => { return err(e) }
}
```

Pattern-binding in conditions does not exist.
```
-- WRONG:
if let Some(x) = maybe_value { ... }

-- CORRECT:
match maybe_value {
    .some(x) => { ... }
    .none    => {}
}
```

Blocks (`{ ... }`) are statements, not expressions. You cannot do:
```
-- WRONG:
let x = { let a = 5; a + 1 }

-- CORRECT:
fn add_one(a: i32) -> i32 { return a + 1 }
let x = add_one(5)
```

use n64.display
use n64.controller
use n64.rdpq
use n64.timer

const SCREEN_W: i32 = 320
const SCREEN_H: i32 = 240
const RECT_SIZE: i32 = 16
const DEAD_ZONE: i32 = 10

entry {
    display.init(0, 2, 3, 0, 1)
    rdpq.init()
    controller.init()
    timer.init()

    let x: i32 = SCREEN_W / 2
    let y: i32 = SCREEN_H / 2

    loop {
        controller.poll()
        let pad = controller.read(0)

        let raw_x: i32 = pad.stick_x as i32
        let raw_y: i32 = pad.stick_y as i32

        let dx: i32 = if raw_x > DEAD_ZONE or raw_x < -DEAD_ZONE { raw_x / 16 } else { 0 }
        let dy: i32 = if raw_y > DEAD_ZONE or raw_y < -DEAD_ZONE { -(raw_y / 16) } else { 0 }

        x = x + dx
        y = y + dy

        if x < 0 { x = 0 }
        if x > SCREEN_W - RECT_SIZE { x = SCREEN_W - RECT_SIZE }
        if y < 0 { y = 0 }
        if y > SCREEN_H - RECT_SIZE { y = SCREEN_H - RECT_SIZE }

        let fb = display.get()
        rdpq.attach_clear(fb)

        rdpq.set_mode_fill(0x000000FF)
        rdpq.fill_rectangle(0, 0, SCREEN_W, SCREEN_H)

        rdpq.sync_pipe()
        rdpq.set_mode_fill(0xFF0000FF)
        rdpq.fill_rectangle(x, y, x + RECT_SIZE, y + RECT_SIZE)

        rdpq.detach_show()
    }
}

